import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { API } from "../api/base";
import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  LineChart,
  Line,
  ResponsiveContainer
} from "recharts";
import "./CompanyAnalytics.scss";

export default function CompanyAnalytics() {
  const [analytics, setAnalytics] = useState(null);
  const token = localStorage.getItem("token");
  const navigate = useNavigate();

  useEffect(() => {
    document.body.classList.add("company-theme");

    const fetchAnalytics = async () => {
      const res = await fetch(
        `${API}/api/company/analytics`,
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      const data = await res.json();
      setAnalytics(data);
    };

    fetchAnalytics();

    return () => {
      document.body.classList.remove("company-theme");
    };
  }, [token]);

  if (!analytics) return <div className="company-page">Loading...</div>;

  /* =========================
     CHART DATA
  ========================= */

  const statusData = [
    { name: "Approved", value: analytics.approvedBugs },
    { name: "Pending", value: analytics.pendingBugs },
    { name: "Rejected", value: analytics.rejectedBugs },
  ];

  const COLORS = ["#2ecc71", "#f1c40f", "#e74c3c"];

  const barData = [
    { name: "Total", value: analytics.totalBugs },
    { name: "Approved", value: analytics.approvedBugs },
    { name: "Rejected", value: analytics.rejectedBugs },
  ];

  const paymentData = [
    { name: "Paid", value: analytics.totalPaid },
    { name: "Wallet", value: analytics.walletBalance },
  ];

  return (
    <div className="company-page">

      <div className="top-bar">
        <button
          className="back-btn"
          onClick={() => navigate("/company")}
        >
          ⬅ Back
        </button>

        <h1>Advanced Analytics</h1>
      </div>

      {/* SUMMARY CARDS */}
      <div className="analytics-grid">
        <div className="stat-box">
          <h3>Total Bugs</h3>
          <p>{analytics.totalBugs}</p>
        </div>

        <div className="stat-box">
          <h3>Total Paid</h3>
          <p>₹{analytics.totalPaid}</p>
        </div>

        <div className="stat-box wallet">
          <h3>Wallet Balance</h3>
          <p>₹{analytics.walletBalance}</p>
        </div>
      </div>

      {/* PIE CHART */}
      <div className="chart-container">
        <h2>Bug Status Distribution</h2>

        <ResponsiveContainer width="100%" height={300}>
          <PieChart>
            <Pie
              data={statusData}
              dataKey="value"
              outerRadius={100}
              label
            >
              {statusData.map((entry, index) => (
                <Cell key={index} fill={COLORS[index]} />
              ))}
            </Pie>
            <Tooltip />
          </PieChart>
        </ResponsiveContainer>
      </div>

      {/* BAR CHART */}
      <div className="chart-container">
        <h2>Bug Overview</h2>

        <ResponsiveContainer width="100%" height={300}>
          <BarChart data={barData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="name" />
            <YAxis />
            <Tooltip />
            <Bar dataKey="value" fill="#3498db" />
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* LINE CHART */}
      <div className="chart-container">
        <h2>Financial Overview</h2>

        <ResponsiveContainer width="100%" height={300}>
          <LineChart data={paymentData}>
            <CartesianGrid strokeDasharray="3 3" />
            <XAxis dataKey="name" />
            <YAxis />
            <Tooltip />
            <Line type="monotone" dataKey="value" stroke="#6dd5ed" />
          </LineChart>
        </ResponsiveContainer>
      </div>

    </div>
  );
}
